  ('dietitian-moex-07179', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '經過聯合國環境總署所正式通過之「生物安全議定書（Biosafety Protocol）」協定，雖然各國擔心基因改 良產品可能危害人體健康，或會破壞自然環境，即使在無法執行評估或缺乏完整科學證據確實有害的情 況下，可採取下列何種措施？ 有權限制此產品進口    不得限制此產品進口 可暫時進口    必須發生實際危害證據方得禁止此產品進口', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07180', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '衛生福利部（原行政院衛生署）所公告之現行「國人膳食營養素參考攝取量」中，各項數值之關係為：', '["EAR＞RDA＞AI＞UL", "EAR＜RDA＜AI＜UL", "RDA＞EAR＞AI＞UL", "RDA＜EAR＜AI＜UL"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07181', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '衛生福利部（原行政院衛生署）所公告之現行「國人膳食營養素參考攝取量」中，0～6個月和7～12個 月嬰兒的蛋白質建議攝取量各為多少？', '["1.2 g/kg，1.0 g/kg", "1.5 g/kg，1.2 g/kg", "2.0 g/kg，1.8 g/kg", "2.3 g/kg，2.1 g/kg"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
